vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float corr = uTexSize.xy*texsize_noise_lq.zw;
vec2 uv1 = vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;


vec3 noiseVal =lum (texture(sampler_noise_lq, corr*vUv*.02+ .1*rand_frame));

vec2 k1 = vec2((vUv.x), (vUv.y));

vec3 ret1 = GetBlur1(vUv) ;

float k2 = (20*vUv)%2;

vec2 zz = vUv.xy * uTexSize.xy *.08;
float h1 = (tan(zz.x));
float h2 = (tan(zz.y));

vUv.xy -= vec2(h1,h2)*uTexSize.zw * 3;


vec3 crisp = texture(sampler_main,vUv) + noiseVal/30;

crisp = mix(crisp, 1-crisp.zyx, 0.01);

 ret = crisp -.03 - 0.2*pow(1-vRadius,18);

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv0 = vUv;
vec2 uv5 = (vUv-.5)*uAspect.xy;

vUv -= 0.5;
vUv *= uAspect.xy;
vUv += vec2 (q5,q6)/4;
vUv = multiply(vUv,mat2(_qb));
uv5 = vUv;

rs0.x = atan(uv5.y, uv5.x)/3.1416*6*q28;
rs0.y = 1/(length(vUv));
//rs0.y = q5* rs0.y + q6 * 1/rs0.y;
rss = vec2 (rs0.x+q9*8,rs0.y+q9*q28*4)/12;


vec3 ret1 = 0;
int anz = 3;
int n = 0;
vec2 ofs = .1*vec2(q5,q6).yx;
while (n <= anz) {
    float dist = fract(-q9+1.0*n/anz);

    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2 = multiply(vUv,q13*dist*mat2(c,s,-s,c))*uAspect.yx;
    uv3 = fract(uv2+.5+ofs) ;
    neu = 1*GetPixel(uv3)+ GetBlur1(uv3)*1;
    ret1 = max(ret1,neu* (1-dist*dist)*2);
n++;
}

vec2 dz = vec2 (ret1.r+ret1.b, ret1.r-ret1.g)/2;
ret = ret1
+ audioLowSmooth*.004/length(vUv)*roam_sin
+ 2*(audioLowSmooth*GetBlur1(fract(rss+dz)).brg+.0*roam_sin*length(vUv))*clamp01(1-ret1*4);
//+ .03/length(sin(vec2(-rs0.x*.0,-rs0.y*5)))*(1/audioHighSmooth)*clamp01(1-ret1*4);
//ret = GetPixel(uv0)*2;

  fragColor = ret;
}
